// Validate batch payload
const body = $input.first().json.body || $input.first().json;

// ── Shell-metacharacter sanitiser (F-1 fix) ──────────────────────────────────
function sanitizeArg(val, fieldName) {
  if (typeof val !== 'string') return val;
  if (/[^a-zA-Z0-9_.\/\-]/.test(val)) {
    throw new Error(
      `Input '${fieldName}' contains disallowed shell characters: ${val}. ` +
      'Only alphanumerics, path separators (/), dots, dashes and underscores are allowed.'
    );
  }
  return val;
}

// ── Path-prefix restriction (F-2 fix) ────────────────────────────────────────
const ALLOWED_PREFIX = '/app/clara_pipeline/data/';
function restrictPath(val, fieldName) {
  if (val && !val.startsWith(ALLOWED_PREFIX)) {
    throw new Error(
      `'${fieldName}' must be within ${ALLOWED_PREFIX}. Got: ${val}`
    );
  }
  return val;
}

const rawDemoDir       = body.demo_dir;
const rawOnboardingDir = body.onboarding_dir;
const rawPairsFile     = body.pairs_file;
const dryRun           = body.dry_run || false;
const force            = body.force   || false;
const rawModel         = body.model   || process.env.OLLAMA_MODEL || 'mistral';
const rawOllamaUrl     = body.ollama_url || process.env.OLLAMA_URL || 'http://host.docker.internal:11434';

if (!rawDemoDir && !rawPairsFile) {
  throw new Error('Provide either demo_dir (with optional onboarding_dir) or pairs_file');
}

// Sanitise and restrict all path inputs
const demoDir       = rawDemoDir       ? restrictPath(sanitizeArg(rawDemoDir,       'demo_dir'),       'demo_dir')       : null;
const onboardingDir = rawOnboardingDir ? restrictPath(sanitizeArg(rawOnboardingDir, 'onboarding_dir'), 'onboarding_dir') : demoDir;
const pairsFile     = rawPairsFile     ? restrictPath(sanitizeArg(rawPairsFile,     'pairs_file'),     'pairs_file')     : null;
const model         = sanitizeArg(rawModel, 'model');
let ollamaUrl;
try {
  const u = new URL(rawOllamaUrl);
  if (!['http:', 'https:'].includes(u.protocol)) throw new Error('protocol');
  ollamaUrl = rawOllamaUrl;
} catch {
  throw new Error(`'ollama_url' is not a valid http/https URL: ${rawOllamaUrl}`);
}

return [{
  json: {
    demo_dir: demoDir,
    onboarding_dir: onboardingDir,
    pairs_file: pairsFile,
    dry_run: dryRun,
    force,
    model,
    ollama_url: ollamaUrl,
    started_at: new Date().toISOString()
  }
}];

// Parse run_all.py output
const stdout = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode;

if (exitCode !== 0) {
  throw new Error(`run_all.py failed (exit ${exitCode}):\n${stdout.slice(0, 1000)}`);
}

// Parse summary table from output
const lines = stdout.split('\n');
const accounts = [];

for (const line of lines) {
  // Match table rows: CLARA-YYYY-NNN  Company  ✓  ✓  ✅
  const match = line.match(/^(CLARA-\d{4}-\d{3})\s+(.+?)\s+(✓|✗)\s+(✓|✗|-)\s*(✅|❌|-)/);
  if (match) {
    accounts.push({
      account_id: match[1],
      company: match[2].trim(),
      v1_ok: match[3] === '✓',
      v2_ok: match[4] === '✓',
      go_live: match[5] === '✅'
    });
  }
}

// Extract elapsed time
const elapsedMatch = stdout.match(/(\d+\.\d+)s/);
const elapsed = elapsedMatch ? parseFloat(elapsedMatch[1]) : null;

// Load run_summary.json if it exists
const fs = require('fs');
let runSummary = {};
const summaryPath = '/app/clara_pipeline/outputs/run_summary.json';
try {
  if (fs.existsSync(summaryPath)) {
    runSummary = JSON.parse(fs.readFileSync(summaryPath, 'utf8'));
  }
} catch(e) {}

const v1Success = accounts.filter(a => a.v1_ok).length;
const v2Success = accounts.filter(a => a.v2_ok).length;
const goLiveReady = accounts.filter(a => a.go_live).length;

return [{
  json: {
    ...($input.first().json),
    accounts_processed: accounts.length,
    v1_success: v1Success,
    v2_success: v2Success,
    go_live_ready: goLiveReady,
    elapsed_seconds: elapsed,
    accounts,
    run_summary: runSummary,
    run_all_stdout: stdout
  }
}];

// Write batch summary to pipeline_log.json
const fs = require('fs');
const logPath = '/app/clara_pipeline/outputs/pipeline_log.json';
let log = [];
try {
  if (fs.existsSync(logPath)) log = JSON.parse(fs.readFileSync(logPath, 'utf8'));
} catch(e) {}

const d = $input.first().json;

const entry = {
  timestamp: new Date().toISOString(),
  pipeline: 'BATCH',
  accounts_processed: d.accounts_processed,
  v1_success: d.v1_success,
  v2_success: d.v2_success,
  go_live_ready: d.go_live_ready,
  elapsed_seconds: d.elapsed_seconds,
  model: d.model,
  dry_run: d.dry_run,
  accounts: d.accounts
};

log.push(entry);
fs.writeFileSync(logPath, JSON.stringify(log, null, 2));

return [{ json: { ...d, log_written: true } }];

